def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    if not isinstance(expr, str):
        return ""

    expr = expr.strip()

    if not expr:
        return ""

    # Whitelist allowed characters: digits, operators, parentheses, decimal point, spaces
    allowed_chars = set("0123456789+-*/.() ")
    if not all(c in allowed_chars for c in expr):
        return ""

    # Prevent common injection patterns
    dangerous_patterns = ["__", "import", "exec", "eval", "lambda", "open", "file"]
    expr_lower = expr.lower()
    if any(pattern in expr_lower for pattern in dangerous_patterns):
        return ""

    try:
        # Use ast.literal_eval with a restricted evaluation approach
        # Parse and validate the expression structure
        import ast
        import operator

        # Create a safe namespace with only allowed operations
        safe_dict = {
            'abs': abs,
            'round': round,
        }

        # Parse the expression as an AST
        tree = ast.parse(expr, mode='eval')

        # Validate that the AST only contains allowed node types
        allowed_node_types = (
            ast.Expression,
            ast.BinOp,
            ast.UnaryOp,
            ast.Constant,
            ast.Num,  # For Python < 3.8 compatibility
            ast.Add,
            ast.Sub,
            ast.Mult,
            ast.Div,
            ast.FloorDiv,
            ast.Mod,
            ast.Pow,
            ast.UAdd,
            ast.USub,
            ast.Call,
            ast.Name,
        )

        def validate_node(node):
            if not isinstance(node, allowed_node_types):
                return False
            if isinstance(node, ast.Call):
                if isinstance(node.func, ast.Name):
                    if node.func.id not in safe_dict:
                        return False
                else:
                    return False
            if isinstance(node, ast.Name):
                if node.id not in safe_dict:
                    return False
            for child in ast.iter_child_nodes(node):
                if not validate_node(child):
                    return False
            return True

        if not validate_node(tree):
            return ""

        # Compile and evaluate the expression
        code = compile(tree, '<string>', 'eval')
        result = eval(code, {"__builtins__": {}}, safe_dict)

        # Convert result to string
        if isinstance(result, float):
            # Handle floating point results
            if result == int(result):
                return str(int(result))
            else:
                return str(result)
        else:
            return str(result)

    except (SyntaxError, ValueError, TypeError, ZeroDivisionError, OverflowError, NameError):
        return ""
    except Exception:
        return ""

import xml.etree.ElementTree as ET


def parse_xml(xml_string):
    '''
    Parse xml_string and return the root element of the XML document
    '''
    try:
        root = ET.fromstring(xml_string)
        return root
    except ET.ParseError as e:
        raise ValueError(f"Invalid XML: {e}")

